function calculateSubscriptionChange(userId, currentPlan, newPlan) {
    const planPrices = {
        'free': 0,
        'pro': 10,
        'enterprise': 50
    };

    if (!planPrices.hasOwnProperty(currentPlan) || !planPrices.hasOwnProperty(newPlan)) {
        throw new Error('Invalid plan name');
    }

    const currentPrice = planPrices[currentPlan];
    const newPrice = planPrices[newPlan];
    const chargeAmount = newPrice - currentPrice;

    return {
        newPlan: newPlan,
        chargeAmount: chargeAmount
    };
}